   301→  const serverDir = path.resolve(__dirname, "../../server");
   302→  const distEntry = path.join(serverDir, "dist", "run.js");
   303→  if (fs.existsSync(distEntry)) {
   304→    return distEntry;
   305→  }
   306→  
   307→  log("Server entry not found at:", distEntry);
   308→  log("Make sure server is building (turbo should run @acc/server dev)");
   309→  return null;
   310→}
   311→
   312→function resolveServerCwd(): string {
   313→  if (app.isPackaged) {
   314→    return path.join(process.resourcesPath, "server");
   315→  }
   316→  return path.resolve(__dirname, "../../server");
   317→}
   318→
   319→/**
   320→ * Build environment variables for the server process.
   321→ * Follows T3 Code pattern of passing config via env.
   322→ */
   323→function buildServerEnv(): NodeJS.ProcessEnv {
   324→  // Get monorepo root for node_modules/.bin
   325→  const monorepoRoot = path.resolve(__dirname, "../../..");
   326→  const nodeModulesBin = path.join(monorepoRoot, "node_modules", ".bin");
   327→  
   328→  // Augment PATH for GUI launches (Spotlight doesn't inherit shell PATH)
   329→  const extraPaths = [
   330→    nodeModulesBin,                              // monorepo binaries (tsx, etc.)
   331→    path.join(os.homedir(), ".local/bin"),       // claude CLI default location
   332→    path.join(os.homedir(), ".cargo/bin"),       // Rust tools
   333→    "/usr/local/bin",
   334→    "/opt/homebrew/bin",
   335→    path.join(os.homedir(), ".nvm/versions/node/v22.15.0/bin"),
   336→    path.join(os.homedir(), ".nvm/versions/node/v20.19.0/bin"),
   337→    path.join(os.homedir(), ".bun/bin"),
   338→  ].join(path.delimiter);
   339→
   340→  return {
   341→    ...process.env,
   342→    PATH: `${extraPaths}${path.delimiter}${process.env.PATH || ""}`,
   343→    ACC_MODE: "desktop",
   344→    ACC_SERVER_PORT: String(serverPort),
   345→    ACC_AUTH_TOKEN: serverAuthToken,
   346→    ACC_STATE_DIR: STATE_DIR,
   347→    ACC_NO_BROWSER: "1",
   348→    NODE_ENV: isDev ? "development" : "production",
   349→    FORCE_COLOR: "0",
   350→  };
   351→}
   352→
   353→async function startServer(): Promise<boolean> {
   354→  if (isQuitting || serverProcess) {
   355→    return false;
   356→  }
   357→
   358→  const serverEntry = resolveServerEntry();
   359→  if (!serverEntry) {
   360→    log("Cannot start server: entry point not found");
   361→    return false;
   362→  }
   363→
   364→  // Reserve port BEFORE spawning (T3 pattern)
   365→  try {
   366→    serverPort = await reservePort(DEFAULT_SERVER_PORT);
   367→    log(`Reserved port ${serverPort}`);
   368→  } catch (err) {
   369→    log("Failed to reserve port:", err);
   370→    return false;
   371→  }
   372→
   373→  // Generate auth token for this session
   374→  serverAuthToken = crypto.randomBytes(24).toString("hex");
   375→
   376→  const cwd = resolveServerCwd();
   377→  const env = buildServerEnv();
   378→  
   379→  log(`Starting server on port ${serverPort}...`);
   380→  log(`Server entry: ${serverEntry}`);
   381→  log(`Server cwd: ${cwd}`);
   382→
   383→  // T3 Code pattern: ALWAYS use Electron itself as Node runtime
   384→  // This works in both dev and production because server is pre-built to JS
   385→  const child = spawn(process.execPath, [serverEntry], {
   386→    cwd,
   387→    env: {
   388→      ...env,
   389→      ELECTRON_RUN_AS_NODE: "1",
   390→    },
   391→    stdio: ["ignore", "pipe", "pipe"],
   392→  });
   393→
   394→  serverProcess = child;
   395→
   396→  // Capture server output
   397→  ensureLogDir();
   398→  const serverLogPath = path.join(LOG_DIR, "server.log");
   399→  const serverLogStream = fs.createWriteStream(serverLogPath, { flags: "a" });
   400→  
   401→  const boundary = `\n=== Server started at ${new Date().toISOString()} pid=${child.pid} port=${serverPort} ===\n`;
   402→  serverLogStream.write(boundary);
   403→  
   404→  child.stdout?.on("data", (data) => {
   405→    serverLogStream.write(data);
   406→    if (isDev) {
   407→      process.stdout.write(`[server] ${data}`);
   408→    }
   409→  });
   410→  
   411→  child.stderr?.on("data", (data) => {
   412→    serverLogStream.write(data);
   413→    if (isDev) {
   414→      process.stderr.write(`[server] ${data}`);
   415→    }
   416→  });
   417→
   418→  child.once("spawn", () => {
   419→    log(`Server process spawned (pid=${child.pid})`);
   420→    restartAttempt = 0;
   421→  });
   422→
   423→  child.on("error", (error) => {
   424→    log("Server process error:", error.message);
   425→    if (serverProcess === child) {
   426→      serverProcess = null;
   427→    }
   428→    scheduleRestart(`error: ${error.message}`);
   429→  });
   430→
   431→  child.on("exit", (code, signal) => {
   432→    log(`Server process exited (code=${code}, signal=${signal})`);
   433→    serverLogStream.write(`\n=== Server exited code=${code} signal=${signal} ===\n`);
   434→    serverLogStream.end();
   435→    
   436→    if (serverProcess === child) {
   437→      serverProcess = null;
   438→    }
   439→    if (!isQuitting) {
   440→      scheduleRestart(`exit code=${code} signal=${signal}`);
   441→    }
   442→  });
   443→
   444→  // Wait for server to be ready
   445→  const ready = await waitForServerReady(serverPort);
   446→  if (ready) {
   447→    log("Server is ready");
   448→  } else {
   449→    log("Server did not become ready in time");
   450→  }
   451→  
   452→  return ready;
   453→}
   454→
   455→function scheduleRestart(reason: string): void {
   456→  if (isQuitting || restartTimer) {
   457→    return;
   458→  }
   459→
   460→  if (restartAttempt >= MAX_RESTART_ATTEMPTS) {
   461→    log(`Server restart limit reached (${MAX_RESTART_ATTEMPTS}), giving up`);
   462→    return;
   463→  }
   464→
   465→  const delayMs = Math.min(
   466→    RESTART_BACKOFF_BASE_MS * Math.pow(2, restartAttempt),
   467→    RESTART_BACKOFF_MAX_MS
   468→  );
   469→  restartAttempt++;
   470→
   471→  log(`Scheduling server restart in ${delayMs}ms (attempt ${restartAttempt}, reason: ${reason})`);
   472→  
   473→  restartTimer = setTimeout(async () => {
   474→    restartTimer = null;
   475→    const started = await startServer();
   476→    if (started) {
   477→      // Notify all windows of new server URL
   478→      for (const win of windowManager.getAll()) {
   479→        win.webContents.send("server-info", {
   480→          port: serverPort,
   481→          apiUrl: `http://127.0.0.1:${serverPort}`,
   482→          wsUrl: `ws://127.0.0.1:${serverPort}`,
   483→        });
   484→      }
   485→    }
   486→  }, delayMs);
   487→}
   488→
   489→function stopServer(): void {
   490→  if (restartTimer) {
   491→    clearTimeout(restartTimer);
   492→    restartTimer = null;
   493→  }
   494→
   495→  const child = serverProcess;
   496→  serverProcess = null;
   497→  
   498→  if (!child) {
   499→    return;
   500→  }
   501→
   502→  log("Stopping server...");
   503→
   504→  // Try graceful shutdown first
   505→  if (child.exitCode === null && child.signalCode === null) {
   506→    child.kill("SIGTERM");
   507→    
   508→    // Force kill after timeout
   509→    setTimeout(() => {
   510→      if (child.exitCode === null && child.signalCode === null) {
   511→        log("Force killing server...");
   512→        child.kill("SIGKILL");
   513→      }
   514→    }, 2000);
   515→  }
   516→}
   517→
   518→// ============ Window Management ============
   519→
   520→async function bootstrap(): Promise<void> {
   521→  log("Bootstrap starting...");
   522→
   523→  // Always start our own server (T3 pattern - no checking for existing)
   524→  const serverStarted = await startServer();
   525→  if (!serverStarted) {
   526→    log("Warning: Server failed to start, app may not work correctly");
   527→  }
   528→
   529→  // Create first window
   530→  windowManager.create();
   531→
   532→  // Create application menu with multi-window support
   533→  createApplicationMenu();
   534→
   535→  log("Bootstrap complete");
   536→}
   537→
   538→function createApplicationMenu(): void {
   539→  const template: Electron.MenuItemConstructorOptions[] = [
   540→    {
   541→      label: APP_NAME,
   542→      submenu: [
   543→        { label: `About ${APP_NAME}`, role: 'about' },
   544→        { type: 'separator' },
   545→        {
   546→          label: 'Settings...',
   547→          accelerator: 'CmdOrCtrl+,',
   548→          click: () => {
   549→            const focusedWindow = BrowserWindow.getFocusedWindow();
   550→            if (focusedWindow) {
   551→              focusedWindow.webContents.send('menu:open-settings');
   552→            }
   553→          }
   554→        },
   555→        { type: 'separator' },
   556→        { role: 'services' },
   557→        { type: 'separator' },
   558→        { role: 'hide' },
   559→        { role: 'hideOthers' },
   560→        { role: 'unhide' },
   561→        { type: 'separator' },
   562→        { role: 'quit' }
   563→      ]
   564→    },
   565→    {
   566→      label: 'File',
   567→      submenu: [
   568→        {
   569→          label: 'New Window',
   570→          accelerator: 'CmdOrCtrl+N',
   571→          click: () => {
   572→            windowManager.create();
   573→          }
   574→        },
   575→        {
   576→          label: 'Open Folder...',
   577→          accelerator: 'CmdOrCtrl+O',
   578→          click: async () => {
   579→            const result = await dialog.showOpenDialog({
   580→              properties: ['openDirectory'],
   581→              title: 'Select Project Folder',
   582→            });
   583→
   584→            if (!result.canceled && result.filePaths.length > 0) {
   585→              windowManager.create(result.filePaths[0]);
   586→            }
   587→          }
   588→        },
   589→        { type: 'separator' },
   590→        { role: 'close' }
   591→      ]
   592→    },
   593→    {
   594→      label: 'Edit',
   595→      submenu: [
   596→        { role: 'undo' },
   597→        { role: 'redo' },
   598→        { type: 'separator' },
   599→        { role: 'cut' },
   600→        { role: 'copy' },
   601→        { role: 'paste' },
   602→        { role: 'selectAll' }
   603→      ]
   604→    },
   605→    {
   606→      label: 'View',
   607→      submenu: [
   608→        { role: 'reload' },
   609→        { role: 'forceReload' },
   610→        { role: 'toggleDevTools' },
   611→        { type: 'separator' },
   612→        { role: 'resetZoom' },
   613→        { role: 'zoomIn' },
   614→        { role: 'zoomOut' },
   615→        { type: 'separator' },
   616→        { role: 'togglefullscreen' }
   617→      ]
   618→    },
   619→    {
   620→      label: 'Window',
   621→      submenu: [
   622→        { role: 'minimize' },
   623→        { role: 'zoom' },
   624→        { type: 'separator' },
   625→        { role: 'front' },
   626→        { type: 'separator' },
   627→        { role: 'window' }
   628→      ]
   629→    }
   630→  ];
   631→
   632→  const menu = Menu.buildFromTemplate(template);
   633→  Menu.setApplicationMenu(menu);
   634→}
   635→
   636→// ============ App Identity (Dev vs Prod) ============
   637→
   638→// Set app name and user data path BEFORE requesting single instance lock
   639→// This allows dev and prod to run simultaneously
   640→app.name = APP_NAME;
   641→app.setPath("userData", path.join(os.homedir(), "Library", "Application Support", USER_DATA_DIR));
   642→
   643→log(`App identity: ${APP_NAME} (isDev=${isDev})`);
   644→log(`User data: ${app.getPath("userData")}`);
   645→
   646→// ============ Single Instance ============
   647→
   648→// Use different instance lock names for dev vs prod
   649→// When a second instance is launched, create a new window instead of quitting
   650→const gotSingleInstanceLock = app.requestSingleInstanceLock({ key: USER_DATA_DIR });
   651→
   652→if (!gotSingleInstanceLock) {
   653→  app.quit();
   654→} else {
   655→  app.on("second-instance", (event, commandLine, workingDirectory) => {
   656→    // Someone tried to run a second instance, create a new window instead
   657→    log("Second instance detected, creating new window");
   658→    windowManager.create();
   659→  });
   660→}
   661→
   662→// ============ App Lifecycle ============
   663→
   664→app.whenReady().then(() => {
   665→  // Set dock icon on macOS (works in dev mode)
   666→  if (process.platform === "darwin" && app.dock) {
   667→    const iconName = isDev ? "icon-dev" : "icon";
   668→    const dockIconPath = path.join(__dirname, "..", "build", `${iconName}.png`);
   669→    if (fs.existsSync(dockIconPath)) {
   670→      app.dock.setIcon(nativeImage.createFromPath(dockIconPath));
   671→      log(`Dock icon set: ${dockIconPath}`);
   672→    } else {
   673→      log(`Dock icon not found: ${dockIconPath}`);
   674→    }
   675→  }
   676→
   677→  bootstrap().catch((error) => {
   678→    log("Bootstrap failed:", error);
   679→    dialog.showErrorBox("Merry failed to start", String(error));
   680→    app.quit();
   681→  });
   682→
   683→  app.on("activate", () => {
   684→    // On macOS, create a new window when clicking the dock icon if no windows exist
   685→    if (windowManager.getCount() === 0) {
   686→      windowManager.create();
   687→    }
   688→  });
   689→});
   690→
   691→app.on("before-quit", () => {
   692→  isQuitting = true;
   693→  isShuttingDown = true;
   694→  stopServer();
   695→});
   696→
   697→app.on("window-all-closed", () => {
   698→  if (process.platform !== "darwin") {
   699→    app.quit();
   700→  }
   701→});
   702→
   703→// Handle SIGINT/SIGTERM for clean shutdown
   704→if (process.platform !== "win32") {
   705→  process.on("SIGINT", () => {
   706→    if (isQuitting) return;
   707→    isQuitting = true;
   708→    isShuttingDown = true;
   709→    stopServer();
   710→    app.quit();
   711→  });
   712→
   713→  process.on("SIGTERM", () => {
   714→    if (isQuitting) return;
   715→    isQuitting = true;
   716→    isShuttingDown = true;
   717→    stopServer();
   718→    app.quit();
   719→  });
   720→}
   721→
   722→// ============ IPC Handlers ============
   723→
   724→// Sync handler for preload to get server URLs
   725→ipcMain.on("server:get-urls", (event) => {
   726→  event.returnValue = {
   727→    apiUrl: `http://127.0.0.1:${serverPort}`,
   728→    wsUrl: `ws://127.0.0.1:${serverPort}`,
   729→  };
   730→});
   731→
   732→// Get server info
   733→ipcMain.handle("server:info", () => {
   734→  return { 
   735→    port: serverPort, 
   736→    pid: serverProcess?.pid,
   737→    apiUrl: `http://127.0.0.1:${serverPort}`,
   738→    wsUrl: `ws://127.0.0.1:${serverPort}`,
   739→  };
   740→});
   741→
   742→// Restart server (for debugging/recovery)
   743→ipcMain.handle("server:restart", async () => {
   744→  log("Manual server restart requested");
   745→  stopServer();
   746→  await new Promise(r => setTimeout(r, 500));
   747→  return startServer();
   748→});
   749→
   750→// Adapter management
   751→ipcMain.handle(
   752→  "adapter:connect",
   753→  async (_event, adapterId: string, config: unknown) => {
   754→    log("Connecting adapter:", adapterId);
   755→    return { ok: true };
   756→  }
   757→);
   758→
   759→ipcMain.handle("adapter:disconnect", async (_event, adapterId: string) => {
   760→  log("Disconnecting adapter:", adapterId);
   761→  return { ok: true };
   762→});
   763→
   764→ipcMain.handle(
   765→  "adapter:send",
   766→  async (_event, adapterId: string, message: string) => {
   767→    log("Sending to adapter:", adapterId);
   768→    return { ok: true, turnId: crypto.randomUUID() };
   769→  }
   770→);
   771→
   772→// Launchers
   773→ipcMain.handle("launcher:cursor", async (_event, projectPath: string) => {
   774→  const { exec } = await import("child_process");
   775→  return new Promise((resolve, reject) => {
   776→    exec(`cursor "${projectPath}"`, (error) => {
   777→      if (error) reject(error);
   778→      else resolve({ ok: true });
   779→    });
   780→  });
   781→});
   782→
   783→ipcMain.handle("launcher:browser", async (_event, url: string) => {
   784→  const { shell } = await import("electron");
   785→  await shell.openExternal(url);
   786→  return { ok: true };
   787→});
   788→
   789→// CodeRabbit CLI
   790→ipcMain.handle("coderabbit:review", async (_event, cwd: string) => {
   791→  const { exec } = await import("child_process");
   792→  return new Promise((resolve, reject) => {
   793→    exec("cr --prompt-only", { cwd }, (error, stdout, stderr) => {
   794→      if (error) reject({ error: error.message, stderr });
   795→      else resolve({ ok: true, output: stdout });
   796→    });
   797→  });
   798→});
   799→
   800→// GitHub CLI
   801→ipcMain.handle(
   802→  "github:createPr",
   803→  async (_event, options: { title: string; body: string; cwd: string }) => {
   804→    const { exec } = await import("child_process");
   805→    return new Promise((resolve, reject) => {
   806→      exec(
   807→        `gh pr create --title "${options.title}" --body "${options.body}"`,
   808→        { cwd: options.cwd },
   809→        (error, stdout, stderr) => {
   810→          if (error) reject({ error: error.message, stderr });
   811→          else resolve({ ok: true, output: stdout });
   812→        }
   813→      );
   814→    });
   815→  }
   816→);
   817→
   818→// Dialog: Open Folder
   819→ipcMain.handle("dialog:openFolder", async (event, defaultPath?: string) => {
   820→  // Get the window that sent the request
   821→  const window = BrowserWindow.fromWebContents(event.sender);
   822→
   823→  const dialogOptions: Electron.OpenDialogOptions = {
   824→    properties: ["openDirectory"],
   825→    title: "Select Project Folder",
   826→    defaultPath: defaultPath || undefined,
   827→  };
   828→
   829→  const result = window
   830→    ? await dialog.showOpenDialog(window, dialogOptions)
   831→    : await dialog.showOpenDialog(dialogOptions);
   832→
   833→  if (result.canceled || result.filePaths.length === 0) {
   834→    return null;
   835→  }
   836→
   837→  return result.filePaths[0];
   838→});
   839→
   840→// Window management IPC handlers
   841→ipcMain.handle("window:create", async (_event, folderPath?: string) => {
   842→  windowManager.create(folderPath);
   843→  return { ok: true };
   844→});
   845→
   846→// ============ Notification Handlers ============
   847→
   848→// Check if any app window is focused
   849→ipcMain.handle("app:is-focused", () => {
   850→  return BrowserWindow.getFocusedWindow() !== null;
   851→});
   852→
   853→// Request notification permission (macOS requires user interaction to trigger permission prompt)
   854→ipcMain.handle("notification:request-permission", async () => {
   855→  if (!Notification.isSupported()) {
   856→    return { ok: false, error: "notifications-not-supported" };
   857→  }
   858→
   859→  // On macOS, showing a notification will trigger the permission prompt if not already granted
   860→  // Create a test notification to trigger the prompt
   861→  const notification = new Notification({
   862→    title: "Notifications Enabled",
   863→    body: "You'll receive notifications when agents complete their tasks.",
   864→    silent: true,
   865→  });
   866→  notification.show();
   867→
   868→  return { ok: true };
   869→});
   870→
   871→// Show native desktop notification (centralized to prevent duplicates across windows)
   872→ipcMain.handle(
   873→  "notification:show",
   874→  async (
   875→    _event,
   876→    options: {
   877→      title: string;
   878→      body: string;
   879→      sound?: boolean;
   880→      onlyWhenUnfocused?: boolean;
   881→      consoleId?: string;
   882→    }
   883→  ) => {
   884→    // If onlyWhenUnfocused is true, skip notification when any window is focused
   885→    if (options.onlyWhenUnfocused && BrowserWindow.getFocusedWindow() !== null) {
   886→      return { ok: true, skipped: true, reason: "app-focused" };
   887→    }
   888→
   889→    // Check if notifications are supported
   890→    if (!Notification.isSupported()) {
   891→      return { ok: false, error: "notifications-not-supported" };
   892→    }
   893→
   894→    const notification = new Notification({
   895→      title: options.title,
   896→      body: options.body,
   897→      // Use native macOS notification sound when sound is enabled
   898→      silent: !options.sound,
   899→    });
   900→
   901→    // Handle notification click - focus app and highlight the console
   902→    notification.on("click", () => {
   903→      // Focus the first window (or any available window)
   904→      const windows = BrowserWindow.getAllWindows();
   905→      if (windows.length > 0) {
   906→        const win = windows[0];
   907→        if (win.isMinimized()) {
   908→          win.restore();
   909→        }
   910→        win.focus();
   911→
   912→        // Send message to renderer to highlight the console
   913→        if (options.consoleId) {
   914→          win.webContents.send("notification:clicked", { consoleId: options.consoleId });
   915→        }
   916→      }
   917→    });
   918→
   919→    notification.show();
   920→
   921→    return { ok: true };
   922→  }
   923→);
   924→

