   418→  const normalizedPath = Path.posix.normalize(rawPath).replace(/^\/+/, "");
   419→  if (normalizedPath.includes("..")) {
   420→    return Path.join(staticRoot, "index.html");
   421→  }
   422→
   423→  const requestedPath = normalizedPath.length > 0 ? normalizedPath : "index.html";
   424→  const resolvedPath = Path.join(staticRoot, requestedPath);
   425→
   426→  if (Path.extname(resolvedPath)) {
   427→    return resolvedPath;
   428→  }
   429→
   430→  const nestedIndex = Path.join(resolvedPath, "index.html");
   431→  if (FS.existsSync(nestedIndex)) {
   432→    return nestedIndex;
   433→  }
   434→
   435→  return Path.join(staticRoot, "index.html");
   436→}
