   652→function resolveResourcePath(fileName: string): string | null {
   653→  const candidates = [
   654→    Path.join(__dirname, "../resources", fileName),
   655→    Path.join(__dirname, "../prod-resources", fileName),
   656→    Path.join(process.resourcesPath, "resources", fileName),
   657→    Path.join(process.resourcesPath, fileName),
   658→  ];
   659→
   660→  for (const candidate of candidates) {
   661→    if (FS.existsSync(candidate)) {
   662→      return candidate;
   663→    }
   664→  }
   665→
   666→  return null;
