   673→/**
   674→ * Resolve the Electron userData directory path.
   675→ *
   676→ * Electron derives the default userData path from `productName` in
   677→ * package.json, which currently produces directories with spaces and
   678→ * parentheses (e.g. `~/.config/T3 Code (Alpha)` on Linux). This is
   679→ * unfriendly for shell usage and violates Linux naming conventions.
   680→ *
   681→ * We override it to a clean lowercase name (`t3code`). If the legacy
   682→ * directory already exists we keep using it so existing users don't
   683→ * lose their Chromium profile data (localStorage, cookies, sessions).
   684→ */
   685→function resolveUserDataPath(): string {
   686→  const appDataBase =
   687→    process.platform === "win32"
   688→      ? process.env.APPDATA || Path.join(OS.homedir(), "AppData", "Roaming")
   689→      : process.platform === "darwin"
   690→        ? Path.join(OS.homedir(), "Library", "Application Support")
   691→        : process.env.XDG_CONFIG_HOME || Path.join(OS.homedir(), ".config");
   692→
   693→  const legacyPath = Path.join(appDataBase, LEGACY_USER_DATA_DIR_NAME);
   694→  if (FS.existsSync(legacyPath)) {
   695→    return legacyPath;
   696→  }
   697→
   698→  return Path.join(appDataBase, USER_DATA_DIR_NAME);
   699→}
