   757→async function checkForUpdates(reason: string): Promise<void> {
   758→  if (isQuitting || !updaterConfigured || updateCheckInFlight) return;
   759→  if (updateState.status === "downloading" || updateState.status === "downloaded") {
   760→    console.info(
   761→      `[desktop-updater] Skipping update check (${reason}) while status=${updateState.status}.`,
   762→    );
   763→    return;
   764→  }
   765→  updateCheckInFlight = true;
   766→  setUpdateState(reduceDesktopUpdateStateOnCheckStart(updateState, new Date().toISOString()));
   767→  console.info(`[desktop-updater] Checking for updates (${reason})...`);
   768→
   769→  try {
   770→    await autoUpdater.checkForUpdates();
   771→  } catch (error: unknown) {
   772→    const message = error instanceof Error ? error.message : String(error);
   773→    setUpdateState(
   774→      reduceDesktopUpdateStateOnCheckFailure(updateState, message, new Date().toISOString()),
   775→    );
   776→    console.error(`[desktop-updater] Failed to check for updates: ${message}`);
   777→  } finally {
   778→    updateCheckInFlight = false;
   779→  }
   780→}
