   782→async function downloadAvailableUpdate(): Promise<{ accepted: boolean; completed: boolean }> {
   783→  if (!updaterConfigured || updateDownloadInFlight || updateState.status !== "available") {
   784→    return { accepted: false, completed: false };
   785→  }
   786→  updateDownloadInFlight = true;
   787→  setUpdateState(reduceDesktopUpdateStateOnDownloadStart(updateState));
   788→  autoUpdater.disableDifferentialDownload = isArm64HostRunningIntelBuild(desktopRuntimeInfo);
   789→  console.info("[desktop-updater] Downloading update...");
   790→
   791→  try {
   792→    await autoUpdater.downloadUpdate();
   793→    return { accepted: true, completed: true };
   794→  } catch (error: unknown) {
   795→    const message = error instanceof Error ? error.message : String(error);
   796→    setUpdateState(reduceDesktopUpdateStateOnDownloadFailure(updateState, message));
   797→    console.error(`[desktop-updater] Failed to download update: ${message}`);
   798→    return { accepted: true, completed: false };
   799→  } finally {
   800→    updateDownloadInFlight = false;
   801→  }
   802→}
   803→
   804→async function installDownloadedUpdate(): Promise<{ accepted: boolean; completed: boolean }> {
   805→  if (isQuitting || !updaterConfigured || updateState.status !== "downloaded") {
   806→    return { accepted: false, completed: false };
   807→  }
   808→
   809→  isQuitting = true;
   810→  clearUpdatePollTimer();
   811→  try {
   812→    await stopBackendAndWaitForExit();
   813→    autoUpdater.quitAndInstall();
   814→    return { accepted: true, completed: true };
   815→  } catch (error: unknown) {
   816→    const message = formatErrorMessage(error);
   817→    isQuitting = false;
   818→    setUpdateState(reduceDesktopUpdateStateOnInstallFailure(updateState, message));
   819→    console.error(`[desktop-updater] Failed to install update: ${message}`);
   820→    return { accepted: true, completed: false };
   821→  }
   822→}
