   824→function configureAutoUpdater(): void {
   825→  const enabled = shouldEnableAutoUpdates();
   826→  setUpdateState({
   827→    ...createInitialDesktopUpdateState(app.getVersion(), desktopRuntimeInfo),
   828→    enabled,
   829→    status: enabled ? "idle" : "disabled",
   830→  });
   831→  if (!enabled) {
   832→    return;
   833→  }
   834→  updaterConfigured = true;
   835→
   836→  const githubToken =
   837→    process.env.T3CODE_DESKTOP_UPDATE_GITHUB_TOKEN?.trim() || process.env.GH_TOKEN?.trim() || "";
   838→  if (githubToken) {
   839→    // When a token is provided, re-configure the feed with `private: true` so
   840→    // electron-updater uses the GitHub API (api.github.com) instead of the
   841→    // public Atom feed (github.com/…/releases.atom) which rejects Bearer auth.
   842→    const appUpdateYml = readAppUpdateYml();
   843→    if (appUpdateYml?.provider === "github") {
   844→      autoUpdater.setFeedURL({
   845→        ...appUpdateYml,
   846→        provider: "github" as const,
   847→        private: true,
   848→        token: githubToken,
   849→      });
   850→    }
   851→  }
   852→
   853→  autoUpdater.autoDownload = false;
   854→  autoUpdater.autoInstallOnAppQuit = false;
   855→  // Keep alpha branding, but force all installs onto the stable update track.
   856→  autoUpdater.channel = DESKTOP_UPDATE_CHANNEL;
   857→  autoUpdater.allowPrerelease = DESKTOP_UPDATE_ALLOW_PRERELEASE;
   858→  autoUpdater.allowDowngrade = false;
   859→  autoUpdater.disableDifferentialDownload = isArm64HostRunningIntelBuild(desktopRuntimeInfo);
   860→  let lastLoggedDownloadMilestone = -1;
   861→
   862→  if (isArm64HostRunningIntelBuild(desktopRuntimeInfo)) {
   863→    console.info(
   864→      "[desktop-updater] Apple Silicon host detected while running Intel build; updates will switch to arm64 packages.",
   865→    );
   866→  }
   867→
   868→  autoUpdater.on("checking-for-update", () => {
   869→    console.info("[desktop-updater] Looking for updates...");
   870→  });
   871→  autoUpdater.on("update-available", (info) => {
   872→    setUpdateState(
   873→      reduceDesktopUpdateStateOnUpdateAvailable(
   874→        updateState,
   875→        info.version,
   876→        new Date().toISOString(),
   877→      ),
   878→    );
   879→    lastLoggedDownloadMilestone = -1;
   880→    console.info(`[desktop-updater] Update available: ${info.version}`);
   881→  });
   882→  autoUpdater.on("update-not-available", () => {
   883→    setUpdateState(reduceDesktopUpdateStateOnNoUpdate(updateState, new Date().toISOString()));
   884→    lastLoggedDownloadMilestone = -1;
   885→    console.info("[desktop-updater] No updates available.");
   886→  });
   887→  autoUpdater.on("error", (error) => {
   888→    const message = formatErrorMessage(error);
   889→    if (!updateCheckInFlight && !updateDownloadInFlight) {
   890→      setUpdateState({
   891→        status: "error",
   892→        message,
   893→        checkedAt: new Date().toISOString(),
   894→        downloadPercent: null,
   895→        errorContext: resolveUpdaterErrorContext(),
   896→        canRetry: updateState.availableVersion !== null || updateState.downloadedVersion !== null,
   897→      });
   898→    }
   899→    console.error(`[desktop-updater] Updater error: ${message}`);
   900→  });
   901→  autoUpdater.on("download-progress", (progress) => {
   902→    const percent = Math.floor(progress.percent);
   903→    if (
   904→      shouldBroadcastDownloadProgress(updateState, progress.percent) ||
   905→      updateState.message !== null
   906→    ) {
   907→      setUpdateState(reduceDesktopUpdateStateOnDownloadProgress(updateState, progress.percent));
   908→    }
   909→    const milestone = percent - (percent % 10);
   910→    if (milestone > lastLoggedDownloadMilestone) {
   911→      lastLoggedDownloadMilestone = milestone;
   912→      console.info(`[desktop-updater] Download progress: ${percent}%`);
   913→    }
   914→  });
   915→  autoUpdater.on("update-downloaded", (info) => {
   916→    setUpdateState(reduceDesktopUpdateStateOnDownloadComplete(updateState, info.version));
   917→    console.info(`[desktop-updater] Update downloaded: ${info.version}`);
   918→  });
   919→
   920→  clearUpdatePollTimer();
   921→
   922→  updateStartupTimer = setTimeout(() => {
   923→    updateStartupTimer = null;
   924→    void checkForUpdates("startup");
   925→  }, AUTO_UPDATE_STARTUP_DELAY_MS);
   926→  updateStartupTimer.unref();
   927→
   928→  updatePollTimer = setInterval(() => {
   929→    void checkForUpdates("poll");
   930→  }, AUTO_UPDATE_POLL_INTERVAL_MS);
   931→  updatePollTimer.unref();
   932→}
   933→function scheduleBackendRestart(reason: string): void {
   934→  if (isQuitting || restartTimer) return;
   935→
   936→  const delayMs = Math.min(500 * 2 ** restartAttempt, 10_000);
   937→  restartAttempt += 1;
   938→  console.error(`[desktop] backend exited unexpectedly (${reason}); restarting in ${delayMs}ms`);
   939→
   940→  restartTimer = setTimeout(() => {
   941→    restartTimer = null;
   942→    startBackend();
   943→  }, delayMs);
   944→}
   945→
   946→function startBackend(): void {
   947→  if (isQuitting || backendProcess) return;
   948→
   949→  const backendEntry = resolveBackendEntry();
   950→  if (!FS.existsSync(backendEntry)) {
   951→    scheduleBackendRestart(`missing server entry at ${backendEntry}`);
   952→    return;
   953→  }
   954→
   955→  const captureBackendLogs = app.isPackaged && backendLogSink !== null;
   956→  const child = ChildProcess.spawn(process.execPath, [backendEntry, "--bootstrap-fd", "3"], {
   957→    cwd: resolveBackendCwd(),
   958→    // In Electron main, process.execPath points to the Electron binary.
   959→    // Run the child in Node mode so this backend process does not become a GUI app instance.
   960→    env: {
   961→      ...backendChildEnv(),
   962→      ELECTRON_RUN_AS_NODE: "1",
   963→    },
   964→    stdio: captureBackendLogs
   965→      ? ["ignore", "pipe", "pipe", "pipe"]
   966→      : ["ignore", "inherit", "inherit", "pipe"],
   967→  });
   968→  const bootstrapStream = child.stdio[3];
   969→  if (bootstrapStream && "write" in bootstrapStream) {
   970→    bootstrapStream.write(
   971→      `${JSON.stringify({
   972→        mode: "desktop",
   973→        noBrowser: true,
   974→        port: backendPort,
   975→        t3Home: BASE_DIR,
   976→        authToken: backendAuthToken,
   977→      })}\n`,
   978→    );
   979→    bootstrapStream.end();
   980→  } else {
   981→    child.kill("SIGTERM");
   982→    scheduleBackendRestart("missing desktop bootstrap pipe");
   983→    return;
   984→  }
   985→  backendProcess = child;
   986→  let backendSessionClosed = false;
   987→  const closeBackendSession = (details: string) => {
   988→    if (backendSessionClosed) return;
   989→    backendSessionClosed = true;
   990→    writeBackendSessionBoundary("END", details);
   991→  };
   992→  writeBackendSessionBoundary(
   993→    "START",
   994→    `pid=${child.pid ?? "unknown"} port=${backendPort} cwd=${resolveBackendCwd()}`,
   995→  );
   996→  captureBackendOutput(child);
   997→
   998→  child.once("spawn", () => {
   999→    restartAttempt = 0;
  1000→  });
  1001→
  1002→  child.on("error", (error) => {
  1003→    if (backendProcess === child) {
  1004→      backendProcess = null;
  1005→    }
  1006→    closeBackendSession(`pid=${child.pid ?? "unknown"} error=${error.message}`);
  1007→    scheduleBackendRestart(error.message);
  1008→  });
  1009→
  1010→  child.on("exit", (code, signal) => {
  1011→    if (backendProcess === child) {
  1012→      backendProcess = null;
  1013→    }
  1014→    closeBackendSession(
  1015→      `pid=${child.pid ?? "unknown"} code=${code ?? "null"} signal=${signal ?? "null"}`,
  1016→    );
  1017→    if (isQuitting) return;
  1018→    const reason = `code=${code ?? "null"} signal=${signal ?? "null"}`;
  1019→    scheduleBackendRestart(reason);
  1020→  });
  1021→}
