  1023→function stopBackend(): void {
  1024→  if (restartTimer) {
  1025→    clearTimeout(restartTimer);
  1026→    restartTimer = null;
  1027→  }
  1028→
  1029→  const child = backendProcess;
  1030→  backendProcess = null;
  1031→  if (!child) return;
  1032→
  1033→  if (child.exitCode === null && child.signalCode === null) {
  1034→    child.kill("SIGTERM");
  1035→    setTimeout(() => {
  1036→      if (child.exitCode === null && child.signalCode === null) {
  1037→        child.kill("SIGKILL");
  1038→      }
  1039→    }, 2_000).unref();
  1040→  }
  1041→}
  1042→
  1043→async function stopBackendAndWaitForExit(timeoutMs = 5_000): Promise<void> {
  1044→  if (restartTimer) {
  1045→    clearTimeout(restartTimer);
  1046→    restartTimer = null;
  1047→  }
  1048→
  1049→  const child = backendProcess;
  1050→  backendProcess = null;
  1051→  if (!child) return;
  1052→  const backendChild = child;
  1053→  if (backendChild.exitCode !== null || backendChild.signalCode !== null) return;
  1054→
  1055→  await new Promise<void>((resolve) => {
  1056→    let settled = false;
  1057→    let forceKillTimer: ReturnType<typeof setTimeout> | null = null;
  1058→    let exitTimeoutTimer: ReturnType<typeof setTimeout> | null = null;
  1059→
  1060→    function settle(): void {
  1061→      if (settled) return;
  1062→      settled = true;
  1063→      backendChild.off("exit", onExit);
  1064→      if (forceKillTimer) {
  1065→        clearTimeout(forceKillTimer);
  1066→      }
  1067→      if (exitTimeoutTimer) {
  1068→        clearTimeout(exitTimeoutTimer);
  1069→      }
  1070→      resolve();
  1071→    }
  1072→
  1073→    function onExit(): void {
  1074→      settle();
  1075→    }
  1076→
  1077→    backendChild.once("exit", onExit);
  1078→    backendChild.kill("SIGTERM");
  1079→
  1080→    forceKillTimer = setTimeout(() => {
  1081→      if (backendChild.exitCode === null && backendChild.signalCode === null) {
  1082→        backendChild.kill("SIGKILL");
  1083→      }
  1084→    }, 2_000);
  1085→    forceKillTimer.unref();
  1086→
  1087→    exitTimeoutTimer = setTimeout(() => {
  1088→      settle();
  1089→    }, timeoutMs);
  1090→    exitTimeoutTimer.unref();
  1091→  });
  1092→}
